export function storeCleanupWithContext(
  tView: TView,
  lView: LView,
  context: any,
  cleanupFn: Function,
): void {
  const lCleanup = getOrCreateLViewCleanup(lView);

  // Historically the `storeCleanupWithContext` was used to register both framework-level and
  // user-defined cleanup callbacks, but over time those two types of cleanups were separated.
  // This dev mode checks assures that user-level cleanup callbacks are _not_ stored in data
  // structures reserved for framework-specific hooks.
  ngDevMode &&
    assertDefined(
      context,
      'Cleanup context is mandatory when registering framework-level destroy hooks',
    );
  lCleanup.push(context);

  if (tView.firstCreatePass) {
    getOrCreateTViewCleanup(tView).push(cleanupFn, lCleanup.length - 1);
  } else {
    // Make sure that no new framework-level cleanup functions are registered after the first
    // template pass is done (and TView data structures are meant to fully constructed).
    if (ngDevMode) {
      Object.freeze(getOrCreateTViewCleanup(tView));
    }
  }
}

export function createComponentLView<T>(
  lView: LView,
  hostTNode: TElementNode,
  def: ComponentDef<T>,
): LView {
  const native = getNativeByTNode(hostTNode, lView) as RElement;
  const tView = getOrCreateComponentTView(def);

  // Only component views should be added to the view tree directly. Embedded views are
  // accessed through their containers because they may be removed / re-added later.
  const rendererFactory = lView[ENVIRONMENT].rendererFactory;
  const componentView = addToEndOfViewTree(
    lView,
    createLView(
      lView,
      tView,
      null,
      getInitialLViewFlagsFromDef(def),
      native,
      hostTNode as TElementNode,
      null,
      rendererFactory.createRenderer(native, def),
      null,
      null,
      null,
    ),
  );

  // Component view will always be created before any injected LContainers,
  // so this is a regular element, wrap it with the component view
  return (lView[hostTNode.index] = componentView);
}

private createComponent(projectableNodes: Node[][]): ComponentInfo {
  const providers: StaticProvider[] = [{provide: $SCOPE, useValue: this.componentScope}];
  const childInjector = Injector.create({
    providers: providers,
    parent: this.parentInjector,
    name: 'DowngradeComponentAdapter',
  });

  const componentRef = createComponent(this.component, {
    elementInjector: childInjector,
    environmentInjector: this.environmentInjector,
    projectableNodes,
    hostElement: this.element[0] as Element,
  });
  const viewChangeDetector = componentRef.injector.get(ChangeDetectorRef);
  const changeDetector = componentRef.changeDetectorRef;

  // testability hook is commonly added during component bootstrap in
  // packages/core/src/application_ref.bootstrap()
  // in downgraded application, component creation will take place here as well as adding the
  // testability hook.
  const testability = componentRef.injector.get(Testability, null);
  if (testability) {
    componentRef.injector
      .get(TestabilityRegistry)
      .registerApplication(componentRef.location.nativeElement, testability);
  }

  hookupNgModel(this.ngModel, componentRef.instance);

  return {viewChangeDetector, componentRef, changeDetector};
}

async installCustomElements(): Promise<void> {
  const { createCustomElement } = await import('@angular/elements');

  const symbolLinkElement = createCustomElement(MarkdownSymbolLinkComponent, {
    injector: this.#injector,
  });
  customElements.define('ngrx-docs-symbol-link', symbolLinkElement);

  const alertElement = createCustomElement(AlertComponent, {
    injector: this.#injector,
  });
  customElements.define('ngrx-docs-alert', alertElement);

  const codeExampleElement = createCustomElement(CodeExampleComponent, {
    injector: this.#injector,
  });
  customElements.define('ngrx-code-example', codeExampleElement);

  const codeTabsElement = createCustomElement(CodeTabsComponent, {
    injector: this.#injector,
  });
  customElements.define('ngrx-code-tabs', codeTabsElement);

  const stackblitzElement = createCustomElement(StackblitzComponent, {
    injector: this.#injector,
  });
  customElements.define('ngrx-docs-stackblitz', stackblitzElement);

  const installInstructionsElement = createCustomElement(
    InstallInstructionsComponent,
    { injector: this.#injector }
  );
  customElements.define('ngrx-docs-install', installInstructionsElement);
}

static fromTicket(ticket: CompilationTicket, adapter: NgCompilerAdapter) {
  switch (ticket.kind) {
    case CompilationTicketKind.Fresh:
      return new NgCompiler(
        adapter,
        ticket.options,
        ticket.tsProgram,
        ticket.programDriver,
        ticket.incrementalBuildStrategy,
        IncrementalCompilation.fresh(
          versionMapFromProgram(ticket.tsProgram, ticket.programDriver),
        ),
        ticket.enableTemplateTypeChecker,
        ticket.usePoisonedData,
        ticket.perfRecorder,
      );
    case CompilationTicketKind.IncrementalTypeScript:
      return new NgCompiler(
        adapter,
        ticket.options,
        ticket.newProgram,
        ticket.programDriver,
        ticket.incrementalBuildStrategy,
        ticket.incrementalCompilation,
        ticket.enableTemplateTypeChecker,
        ticket.usePoisonedData,
        ticket.perfRecorder,
      );
    case CompilationTicketKind.IncrementalResource:
      const compiler = ticket.compiler;
      compiler.updateWithChangedResources(ticket.modifiedResourceFiles, ticket.perfRecorder);
      return compiler;
  }
}

private _reflectDecorator(node: ts.Decorator): Decorator | null {
  // Attempt to resolve the decorator expression into a reference to a concrete Identifier. The
  // expression may contain a call to a function which returns the decorator function, in which
  // case we want to return the arguments.
  let decoratorExpr: ts.Expression = node.expression;
  let args: ts.Expression[] | null = null;

  // Check for call expressions.
  if (ts.isCallExpression(decoratorExpr)) {
    args = Array.from(decoratorExpr.arguments);
    decoratorExpr = decoratorExpr.expression;
  }

  // The final resolved decorator should be a `ts.Identifier` - if it's not, then something is
  // wrong and the decorator can't be resolved statically.
  if (!isDecoratorIdentifier(decoratorExpr)) {
    return null;
  }

  const decoratorIdentifier = ts.isIdentifier(decoratorExpr) ? decoratorExpr : decoratorExpr.name;
  const importDecl = this.getImportOfIdentifier(decoratorIdentifier);

  return {
    name: decoratorIdentifier.text,
    identifier: decoratorExpr,
    import: importDecl,
    node,
    args,
  };
}

private getTemplateContextCompletions(
  context: TmplAstTemplate | null,
): Map<string, ReferenceCompletion | VariableCompletion | LetDeclarationCompletion> | null {
  if (this.templateContextCache.has(context)) {
    return this.templateContextCache.get(context)!;
  }

  const templateContext = new Map<
    string,
    ReferenceCompletion | VariableCompletion | LetDeclarationCompletion
  >();

  // The bound template already has details about the references and variables in scope in the
  // `context` template - they just need to be converted to `Completion`s.
  for (const node of this.data.boundTarget.getEntitiesInScope(context)) {
    if (node instanceof TmplAstReference) {
      templateContext.set(node.name, {
        kind: CompletionKind.Reference,
        node,
      });
    } else if (node instanceof TmplAstLetDeclaration) {
      templateContext.set(node.name, {
        kind: CompletionKind.LetDeclaration,
        node,
      });
    } else {
      templateContext.set(node.name, {
        kind: CompletionKind.Variable,
        node,
      });
    }
  }

  this.templateContextCache.set(context, templateContext);
  return templateContext;
}

function inferBoundAttribute(name: string): {attrName: string; type: BindingType} {
  const attrPrefix = 'attr.';
  const classPrefix = 'class.';
  const stylePrefix = 'style.';
  const animationPrefix = 'animate.';
  const legacyAnimationPrefix = '@';
  let attrName: string;
  let type: BindingType;

  // Infer the binding type based on the prefix.
  if (name.startsWith(attrPrefix)) {
    attrName = name.slice(attrPrefix.length);
    type = BindingType.Attribute;
  } else if (name.startsWith(classPrefix)) {
    attrName = name.slice(classPrefix.length);
    type = BindingType.Class;
  } else if (name.startsWith(stylePrefix)) {
    attrName = name.slice(stylePrefix.length);
    type = BindingType.Style;
  } else if (name.startsWith(animationPrefix)) {
    attrName = name;
    type = BindingType.Animation;
  } else if (name.startsWith(legacyAnimationPrefix)) {
    attrName = name.slice(legacyAnimationPrefix.length);
    type = BindingType.LegacyAnimation;
  } else {
    attrName = name;
    type = BindingType.Property;
  }

  return {attrName, type};
}

private deactivateRouteAndOutlet(
  route: TreeNode<ActivatedRoute>,
  parentContexts: ChildrenOutletContexts,
): void {
  const context = parentContexts.getContext(route.value.outlet);
  // The context could be `null` if we are on a componentless route but there may still be
  // children that need deactivating.
  const contexts = context && route.value.component ? context.children : parentContexts;
  const children: {[outletName: string]: TreeNode<ActivatedRoute>} = nodeChildrenAsMap(route);

  for (const treeNode of Object.values(children)) {
    this.deactivateRouteAndItsChildren(treeNode, contexts);
  }

  if (context) {
    if (context.outlet) {
      // Destroy the component
      context.outlet.deactivate();
      // Destroy the contexts for all the outlets that were in the component
      context.children.onOutletDeactivated();
    }
    // Clear the information about the attached component on the context but keep the reference to
    // the outlet. Clear even if outlet was not yet activated to avoid activating later with old
    // info
    context.attachRef = null;
    context.route = null;
  }
}

private _removeGlobalListeners(elementInfo: MonitoredElementInfo) {
  const rootNode = elementInfo.rootNode;

  if (this._rootNodeFocusListenerCount.has(rootNode)) {
    const rootNodeFocusListeners = this._rootNodeFocusListenerCount.get(rootNode)!;

    if (rootNodeFocusListeners > 1) {
      this._rootNodeFocusListenerCount.set(rootNode, rootNodeFocusListeners - 1);
    } else {
      rootNode.removeEventListener(
        'focus',
        this._rootNodeFocusAndBlurListener,
        captureEventListenerOptions,
      );
      rootNode.removeEventListener(
        'blur',
        this._rootNodeFocusAndBlurListener,
        captureEventListenerOptions,
      );
      this._rootNodeFocusListenerCount.delete(rootNode);
    }
  }

  // Unregister global listeners when last element is unmonitored.
  if (!--this._monitoredElementCount) {
    const window = this._getWindow();
    window.removeEventListener('focus', this._windowFocusListener);

    // Equivalently, stop our InputModalityDetector subscription.
    this._stopInputModalityDetector.next();

    // Clear timeouts for all potentially pending timeouts to prevent the leaks.
    clearTimeout(this._windowFocusTimeoutId);
    clearTimeout(this._originTimeoutId);
  }
}

export function ivyTransformFactory(
  compilation: TraitCompiler,
  reflector: ReflectionHost,
  importRewriter: ImportRewriter,
  defaultImportTracker: DefaultImportTracker,
  localCompilationExtraImportsTracker: LocalCompilationExtraImportsTracker | null,
  perf: PerfRecorder,
  isCore: boolean,
  isClosureCompilerEnabled: boolean,
  emitDeclarationOnly: boolean,
  refEmitter: ReferenceEmitter | null,
  enableTypeReification: boolean,
): ts.TransformerFactory<ts.SourceFile> {
  const recordWrappedNode = createRecorderFn(defaultImportTracker);
  return (context: ts.TransformationContext): ts.Transformer<ts.SourceFile> => {
    return (file: ts.SourceFile): ts.SourceFile => {
      return perf.inPhase(PerfPhase.Compile, () =>
        transformIvySourceFile(
          compilation,
          context,
          reflector,
          importRewriter,
          localCompilationExtraImportsTracker,
          file,
          isCore,
          isClosureCompilerEnabled,
          emitDeclarationOnly,
          refEmitter,
          enableTypeReification,
          recordWrappedNode,
        ),
      );
    };
  };
}

duplicateTemplateVar(
  id: TypeCheckId,
  variable: TmplAstVariable,
  firstDecl: TmplAstVariable,
): void {
  const mapping = this.resolver.getTemplateSourceMapping(id);
  const errorMsg = `Cannot redeclare variable '${variable.name}' as it was previously declared elsewhere for the same template.`;

  // The allocation of the error here is pretty useless for variables declared in microsyntax,
  // since the sourceSpan refers to the entire microsyntax property, not a span for the specific
  // variable in question.
  //
  // TODO(alxhub): allocate to a tighter span once one is available.
  this._diagnostics.push(
    makeTemplateDiagnostic(
      id,
      mapping,
      variable.sourceSpan,
      ts.DiagnosticCategory.Error,
      ngErrorCode(ErrorCode.DUPLICATE_VARIABLE_DECLARATION),
      errorMsg,
      [
        {
          text: `The variable '${firstDecl.name}' was first declared here.`,
          start: firstDecl.sourceSpan.start.offset,
          end: firstDecl.sourceSpan.end.offset,
          sourceFile: mapping.node.getSourceFile(),
        },
      ],
    ),
  );
}

private getElementAttributeCompletionSymbol(
  this: ElementAttributeCompletionBuilder,
  attribute: string,
): ts.Symbol | undefined {
  const {name} = stripBindingSugar(attribute);

  let element: TmplAstElement | TmplAstTemplate;
  if (this.node instanceof TmplAstElement || this.node instanceof TmplAstTemplate) {
    element = this.node;
  } else if (
    this.nodeParent instanceof TmplAstElement ||
    this.nodeParent instanceof TmplAstTemplate
  ) {
    element = this.nodeParent;
  } else {
    // Nothing to do without an element to process.
    return undefined;
  }

  const attrTable = buildAttributeCompletionTable(
    this.component,
    element,
    this.compiler.getTemplateTypeChecker(),
    this.tsLS,
    true,
  );

  if (!attrTable.has(name)) {
    return undefined;
  }

  const completion = attrTable.get(name)!;
  return (
    getAttributeCompletionSymbol(
      completion.kind,
      'directive' in completion ? completion.directive : null,
      'classPropertyName' in completion ? completion.classPropertyName : null,
      this.typeChecker,
      this.tsLS,
    ) ?? undefined
  );
}

export function potentialImportsToExpressions(
  potentialImports: PotentialImport[],
  toFile: ts.SourceFile,
  tracker: ChangeTracker,
  importRemapper?: DeclarationImportsRemapper,
): ts.Expression[] {
  const processedDependencies = importRemapper
    ? importRemapper(potentialImports)
    : potentialImports;

  return processedDependencies.map((importLocation) => {
    if (importLocation.moduleSpecifier) {
      return tracker.addImport(toFile, importLocation.symbolName, importLocation.moduleSpecifier);
    }

    const identifier = ts.factory.createIdentifier(importLocation.symbolName);
    if (!importLocation.isForwardReference) {
      return identifier;
    }

    const forwardRefExpression = tracker.addImport(toFile, 'forwardRef', '@angular/core');
    const arrowFunction = ts.factory.createArrowFunction(
      undefined,
      undefined,
      [],
      undefined,
      undefined,
      identifier,
    );

    return ts.factory.createCallExpression(forwardRefExpression, undefined, [arrowFunction]);
  });
}

export function replaceImport(
  node: ts.NamedImports,
  existingImport: string,
  newImportName: string,
) {
  const isAlreadyImported = findImportSpecifier(node.elements, newImportName);
  if (isAlreadyImported) {
    return node;
  }

  const existingImportNode = findImportSpecifier(node.elements, existingImport);
  if (!existingImportNode) {
    return node;
  }

  const importPropertyName = existingImportNode.propertyName
    ? ts.factory.createIdentifier(newImportName)
    : undefined;
  const importName = existingImportNode.propertyName
    ? existingImportNode.name
    : ts.factory.createIdentifier(newImportName);

  return ts.factory.updateNamedImports(node, [
    ...node.elements.filter((current) => current !== existingImportNode),
    // Create a new import while trying to preserve the alias of the old one.
    ts.factory.createImportSpecifier(false, importPropertyName, importName),
  ]);
}

override ngAfterViewInit(): void {
  super.ngAfterViewInit();

  // Prior to #30314 the stepper had animation `done` events bound to each animated container.
  // The animations module was firing them on initialization and for each subsequent animation.
  // Since the events were bound in the template, it had the unintended side-effect of triggering
  // change detection as well. It appears that this side-effect ended up being load-bearing,
  // because it was ensuring that the content elements (e.g. `matStepLabel`) that are defined
  // in sub-components actually get picked up in a timely fashion. This subscription simulates
  // the same change detection by using `queueMicrotask` similarly to the animations module.
  if (typeof queueMicrotask === 'function') {
    let hasEmittedInitial = false;
    this._animatedContainers.changes
      .pipe(startWith(null), takeUntil(this._destroyed))
      .subscribe(() =>
        queueMicrotask(() => {
          // Simulate the initial `animationDone` event
          // that gets emitted by the animations module.
          if (!hasEmittedInitial) {
            hasEmittedInitial = true;
            this.animationDone.emit();
          }

          this._stateChanged();
        }),
      );
  }
}

function levelSerializer(
  instance: any,
  propName: string | number,
  isReadonly: boolean,
  currentLevel = 0,
  level = MAX_LEVEL,
  continuation = levelSerializer,
): Descriptor {
  let serializableInstance: any;
  try {
    serializableInstance = instance[propName];
  } catch {
    return {
      type: PropType.Error,
      value: '',
      containerType: null,
      editable: false,
      expandable: false,
      preview: '',
    };
  }

  const propData: PropertyData = {
    prop: serializableInstance,
    type: getPropType(serializableInstance),
    containerType: getContainerType(serializableInstance),
  };

  switch (propData.type) {
    case PropType.Array:
    case PropType.Object:
      return createLevelSerializedDescriptor(
        instance,
        propName,
        propData,
        {level, currentLevel},
        continuation,
      );
    default:
      return createShallowSerializedDescriptor(instance, propName, propData, isReadonly);
  }
}

function insertFileOverviewComment(
  sf: ts.SourceFile,
  fileoverview: FileOverviewMeta,
): ts.SourceFile {
  const {comments, host, trailing} = fileoverview;
  // If host statement is no longer the first one, it means that extra statements were added at the
  // very beginning, so we need to relocate @fileoverview comment and cleanup the original statement
  // that hosted it.
  if (sf.statements.length > 0 && host !== sf.statements[0]) {
    if (trailing) {
      ts.setSyntheticTrailingComments(host, undefined);
    } else {
      ts.setSyntheticLeadingComments(host, undefined);
    }

    // Note: Do not use the first statement as it may be elided at runtime.
    // E.g. an import declaration that is type only.
    const commentNode = ts.factory.createNotEmittedStatement(sf);
    ts.setSyntheticLeadingComments(commentNode, comments);

    return ts.factory.updateSourceFile(
      sf,
      [commentNode, ...sf.statements],
      sf.isDeclarationFile,
      sf.referencedFiles,
      sf.typeReferenceDirectives,
      sf.hasNoDefaultLib,
      sf.libReferenceDirectives,
    );
  }
  return sf;
}

constructor(fileOrCursor: ParseSourceFile | PlainCharacterCursor, range?: LexerRange) {
  if (fileOrCursor instanceof PlainCharacterCursor) {
    this.file = fileOrCursor.file;
    this.input = fileOrCursor.input;
    this.end = fileOrCursor.end;

    const state = fileOrCursor.state;
    // Note: avoid using `{...fileOrCursor.state}` here as that has a severe performance penalty.
    // In ES5 bundles the object spread operator is translated into the `__assign` helper, which
    // is not optimized by VMs as efficiently as a raw object literal. Since this constructor is
    // called in tight loops, this difference matters.
    this.state = {
      peek: state.peek,
      offset: state.offset,
      line: state.line,
      column: state.column,
    };
  } else {
    if (!range) {
      throw new Error(
        'Programming error: the range argument must be provided with a file argument.',
      );
    }
    this.file = fileOrCursor;
    this.input = fileOrCursor.content;
    this.end = range.endPos;
    this.state = {
      peek: -1,
      offset: range.startPos,
      line: range.startLine,
      column: range.startCol,
    };
  }
}

private _consumeBlockClose(token: BlockCloseToken) {
  const initialStackLength = this._containerStack.length;
  const topNode = this._containerStack[initialStackLength - 1];
  if (!this._popContainer(null, html.Block, token.sourceSpan)) {
    if (this._containerStack.length < initialStackLength) {
      const nodeName = topNode instanceof html.Component ? topNode.fullName : topNode.name;
      this.errors.push(
        TreeError.create(
          null,
          token.sourceSpan,
          `Unexpected closing block. The block may have been closed earlier. ` +
            `Did you forget to close the <${nodeName}> element? ` +
            `If you meant to write the \`}\` character, you should use the "&#125;" ` +
            `HTML entity instead.`,
        ),
      );
      return;
    }

    this.errors.push(
      TreeError.create(
        null,
        token.sourceSpan,
        `Unexpected closing block. The block may have been closed earlier. ` +
          `If you meant to write the \`}\` character, you should use the "&#125;" ` +
          `HTML entity instead.`,
      ),
    );
  }
}

function migrateParameter(
  node: ts.ParameterDeclaration,
  options: MigrationOptions,
  localTypeChecker: ts.TypeChecker,
  printer: ts.Printer,
  tracker: ChangeTracker,
  superCall: ts.CallExpression | null,
  usedInSuper: boolean,
  usedInConstructor: boolean,
  usesOtherParams: boolean,
  memberIndentation: string,
  innerIndentation: string,
  prependToConstructor: string[],
  propsToAdd: string[],
  afterSuper: string[],
): void {
  const context: ParameterMigrationContext = {
    node,
    options,
    localTypeChecker,
    printer,
    tracker,
    superCall,
    usedInSuper,
    usedInConstructor,
    usesOtherParams,
    memberIndentation,
    innerIndentation,
    prependToConstructor,
    propsToAdd,
    afterSuper,
  };

  if (ts.isIdentifier(node.name)) {
    migrateIdentifierParameter(context, node.name);
  } else if (ts.isObjectBindingPattern(node.name)) {
    migrateObjectBindingParameter(context, node.name);
  } else {
    return;
  }
}

function analyzeRouterTestingModuleUsage(usage: RouterTestingModuleUsage): RouterTestingAnalysis {
  const neededProviders = new Set<ts.Expression>();
  const neededImports = new Set<ts.Expression>();
  let hasLocationMocks = false;

  const optionsExpression = usage.optionsNode ? usage.optionsNode : undefined;
  const routesExpression = getRoutesArgumentForMigration(usage.routesNode, usage.optionsNode);

  // Add RouterModule to imports (preserve options when present)
  const routerModuleExpression = createRouterModuleExpression(routesExpression, optionsExpression);
  neededImports.add(routerModuleExpression);

  // Add location mocks ONLY if:
  // 1. SpyLocation is imported from @angular/common/testing, AND
  // 2. urlChanges property is accessed in the test
  // 3. provideLocationMocks() is not already present
  if (usage.usesSpyLocationUrlChanges) {
    const provideLocationMocksExpression = createProviderCallExpression(PROVIDE_LOCATION_MOCKS);
    neededProviders.add(provideLocationMocksExpression);
    hasLocationMocks = true;
  }

  return {
    neededProviders,
    neededImports,
    canRemoveRouterTestingModule: true,
    replacementCount: 1,
    hasLocationMocks,
  };
}

private getQuickInfoForSymbol(symbol: Symbol): ts.QuickInfo | undefined {
  switch (symbol.kind) {
    case SymbolKind.Input:
    case SymbolKind.Output:
      return this.getQuickInfoForBindingSymbol(symbol);
    case SymbolKind.Template:
      return createNgTemplateQuickInfo(this.node);
    case SymbolKind.Element:
      return this.getQuickInfoForElementSymbol(symbol);
    case SymbolKind.Variable:
      return this.getQuickInfoForVariableSymbol(symbol);
    case SymbolKind.LetDeclaration:
      return this.getQuickInfoForLetDeclarationSymbol(symbol);
    case SymbolKind.Reference:
      return this.getQuickInfoForReferenceSymbol(symbol);
    case SymbolKind.DomBinding:
      return this.getQuickInfoForDomBinding(symbol);
    case SymbolKind.Pipe:
      return this.getQuickInfoForPipeSymbol(symbol);
    case SymbolKind.SelectorlessComponent:
    case SymbolKind.SelectorlessDirective:
      return this.getQuickInfoForSelectorlessSymbol(symbol);
    case SymbolKind.Expression:
      return this.getQuickInfoAtTcbLocation(symbol.tcbLocation);
    case SymbolKind.Directive:
      return this.getQuickInfoForDirectiveSymbol(symbol);
  }
}

private decoratePreventDefault(eventHandler: Function): Function {
  // `DebugNode.triggerEventHandler` needs to know if the listener was created with
  // decoratePreventDefault or is a listener added outside the Angular context so it can handle
  // the two differently. In the first case, the special '__ngUnwrap__' token is passed to the
  // unwrap the listener (see below).
  return (event: any) => {
    // Ivy uses '__ngUnwrap__' as a special token that allows us to unwrap the function
    // so that it can be invoked programmatically by `DebugNode.triggerEventHandler`. The
    // debug_node can inspect the listener toString contents for the existence of this special
    // token. Because the token is a string literal, it is ensured to not be modified by compiled
    // code.
    if (event === '__ngUnwrap__') {
      return eventHandler;
    }

    // Run the event handler inside the ngZone because event handlers are not patched
    // by Zone on the server. This is required only for tests.
    const allowDefaultBehavior =
      typeof ngServerMode !== 'undefined' && ngServerMode
        ? this.ngZone.runGuarded(() => eventHandler(event))
        : eventHandler(event);
    if (allowDefaultBehavior === false) {
      event.preventDefault();
    }

    return undefined;
  };
}

export function getOriginals(
  etm: ElementToMigrate,
  tmpl: string,
  offset: number,
): {start: string; end: string; childLength: number; children: string[]; childNodes: Node[]} {
  // original opening block
  if (etm.el.children.length > 0) {
    const childStart = etm.el.children[0].sourceSpan.start.offset - offset;
    const childEnd = etm.el.children[etm.el.children.length - 1].sourceSpan.end.offset - offset;
    const start = tmpl.slice(
      etm.el.sourceSpan.start.offset - offset,
      etm.el.children[0].sourceSpan.start.offset - offset,
    );
    // original closing block
    const end = tmpl.slice(
      etm.el.children[etm.el.children.length - 1].sourceSpan.end.offset - offset,
      etm.el.sourceSpan.end.offset - offset,
    );
    const childLength = childEnd - childStart;
    return {
      start,
      end,
      childLength,
      children: getOriginalChildren(etm.el.children, tmpl, offset),
      childNodes: etm.el.children,
    };
  }
  // self closing or no children
  const start = tmpl.slice(
    etm.el.sourceSpan.start.offset - offset,
    etm.el.sourceSpan.end.offset - offset,
  );
  // original closing block
  return {start, end: '', childLength: 0, children: [], childNodes: []};
}

export function projectFile(
  file: ts.SourceFile | AbsoluteFsPath,
  {sortedRootDirs, projectRoot}: Pick<ProgramInfo, 'sortedRootDirs' | 'projectRoot'>,
): ProjectFile {
  const fs = getFileSystem();
  const filePath = fs.resolve(typeof file === 'string' ? file : file.fileName);

  // Sorted root directories are sorted longest to shortest. First match
  // is the appropriate root directory for ID computation.
  for (const rootDir of sortedRootDirs) {
    if (!isWithinBasePath(fs, rootDir, filePath)) {
      continue;
    }
    return {
      id: fs.relative(rootDir, filePath) as string as ProjectFileID,
      rootRelativePath: fs.relative(projectRoot, filePath) as string as ProjectRootRelativePath,
    };
  }

  // E.g. project directory may be `src/`, but files may be looked up
  // from `node_modules/`. This is fine, but in those cases, no root
  // directory matches.
  const rootRelativePath = fs.relative(projectRoot, filePath);
  return {
    id: rootRelativePath as string as ProjectFileID,
    rootRelativePath: rootRelativePath as string as ProjectRootRelativePath,
  };
}

visitStagger(ast: StaggerAst, context: AnimationTimelineContext) {
  const parentContext = context.parentContext!;
  const tl = context.currentTimeline;
  const timings = ast.timings;
  const duration = Math.abs(timings.duration);
  const maxTime = duration * (context.currentQueryTotal - 1);
  let delay = duration * context.currentQueryIndex;

  let staggerTransformer = timings.duration < 0 ? 'reverse' : timings.easing;
  switch (staggerTransformer) {
    case 'reverse':
      delay = maxTime - delay;
      break;
    case 'full':
      delay = parentContext.currentStaggerTime;
      break;
  }

  const timeline = context.currentTimeline;
  if (delay) {
    timeline.delayNextStep(delay);
  }

  const startingTime = timeline.currentTime;
  visitDslNode(this, ast.animation, context);
  context.previousNode = ast;

  // time = duration + delay
  // the reason why this computation is so complex is because
  // the inner timeline may either have a delay value or a stretched
  // keyframe depending on if a subtimeline is not used or is used.
  parentContext.currentStaggerTime =
    tl.currentTime - startingTime + (tl.startTime - parentContext.currentTimeline.startTime);
}

export function formatCurrency(
  value: number,
  locale: string,
  currency: string,
  currencyCode?: string,
  digitsInfo?: string,
): string {
  const format = getLocaleNumberFormat(locale, NumberFormatStyle.Currency);
  const pattern = parseNumberFormat(format, getLocaleNumberSymbol(locale, NumberSymbol.MinusSign));

  pattern.minFrac = getNumberOfCurrencyDigits(currencyCode!);
  pattern.maxFrac = pattern.minFrac;

  const res = formatNumberToLocaleString(
    value,
    pattern,
    locale,
    NumberSymbol.CurrencyGroup,
    NumberSymbol.CurrencyDecimal,
    digitsInfo,
  );
  return (
    res
      .replace(CURRENCY_CHAR, currency)
      // if we have 2 time the currency character, the second one is ignored
      .replace(CURRENCY_CHAR, '')
      // If there is a spacing between currency character and the value and
      // the currency character is suppressed by passing an empty string, the
      // spacing character would remain as part of the string. Then we
      // should remove it.
      .trim()
  );
}
